#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_N 9

int cols[MAX_N];
int diag1[2*MAX_N]; // row - col + N - 1
int diag2[2*MAX_N]; // row + col
char board[MAX_N][MAX_N+1];
int n;

void print_solution() {
    for (int i = 0; i < n; ++i) {
        printf("%s\n", board[i]);
    }
    printf("\n");
}

void backtrack(int row) {
    if (row == n) {
        print_solution();
        return;
    }
    for (int col = 0; col < n; ++col) {
        int d1 = row - col + n - 1;
        int d2 = row + col;
        if (!cols[col] && !diag1[d1] && !diag2[d2]) {
            board[row][col] = 'Q';
            cols[col] = diag1[d1] = diag2[d2] = 1;
            backtrack(row + 1);
            cols[col] = diag1[d1] = diag2[d2] = 0;
            board[row][col] = '.';
        }
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &n) != 1) break;
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) board[i][j] = '.';
            board[i][n] = '\0';
        }
        memset(cols, 0, sizeof(cols));
        memset(diag1, 0, sizeof(diag1));
        memset(diag2, 0, sizeof(diag2));
        backtrack(0);
    }
    return 0;
}

