import java.io.*;
import java.util.*;

public class Main {
    static int n;
    static boolean[] colUsed, diag1Used, diag2Used;
    static char[][] board;

    static void printSolution(StringBuilder out) {
        for (int i = 0; i < n; i++) {
            out.append(board[i]);
            out.append('\n');
        }
        out.append('\n');
    }

    static void dfs(int row, StringBuilder out) {
        if (row == n) {
            printSolution(out);
            return;
        }
        for (int col = 0; col < n; col++) {
            int d1 = row - col + n - 1;
            int d2 = row + col;
            if (!colUsed[col] && !diag1Used[d1] && !diag2Used[d2]) {
                board[row][col] = 'Q';
                colUsed[col] = diag1Used[d1] = diag2Used[d2] = true;
                dfs(row + 1, out);
                colUsed[col] = diag1Used[d1] = diag2Used[d2] = false;
                board[row][col] = '.';
            }
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder output = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            n = Integer.parseInt(br.readLine().trim());
            board = new char[n][n];
            for (int i = 0; i < n; i++) Arrays.fill(board[i], '.');
            colUsed = new boolean[n];
            diag1Used = new boolean[2 * n];
            diag2Used = new boolean[2 * n];
            dfs(0, output);
        }
        System.out.print(output.toString());
    }
}

